SELECT 
FROM violation v
JOIN `user` u ON v.user_id = u.user_id
JOIN device d ON v.device_id = d.device_id
JOIN borrow_apply ba ON v.borrow_record_id = ba.apply_id

    v.user_id = #{userId}

        AND
        v.device_id = #{deviceId}


        AND
        v.status = #{status}


ORDER BY v.violation_id DESC
LIMIT #{offset}, #{size}

SELECT COUNT(1)
FROM violation v

    v.user_id = #{userId}

        AND
        v.device_id = #{deviceId}


        AND
        v.status = #{status}

SELECT COALESCE(SUM(
        DATEDIFF(LEAST(end_date, #{endDate}), GREATEST(start_date, #{startDate}))
), 0)
FROM borrow_apply
WHERE device_id = #{deviceId}
  AND start_date < #{endDate}
  AND #{startDate} < end_date
  AND status IN ('approved', 'borrowed', 'returned')
